//! Demonstration front for monster-badchild.
//!
//! This drives the decision pipeline over a handful of representative callers so
//! you can see the rogue's contract: every caller gets a 200, but only the
//! authorized, unobserved one reaches the real moonshine. The rest land in
//! shadow, indistinguishably. The live HTTP server and the leased
//! process-containment gateway are the next layer; this binary exercises the
//! core decision logic.

use a0n_auth::ucan::issue;
use a0n_auth::{IssueOptions, Keypair, RevocationSet};
use monster_swarm::budget::{FleetBudget, FleetProfile};

use monster_badchild::camouflage::Observer;
use monster_badchild::detect::ObservationLedger;
use monster_badchild::gateway::ProcessGateway;
use monster_badchild::mesh::Gap;
use monster_badchild::policy::{Policy, Verdict};
use monster_badchild::portal::{world_key, ShadowWorld};
use monster_badchild::shadow::ShadowEngine;
use monster_badchild::{server, Badchild, Gateway, Incoming, MockGateway};

fn rogue(gateway: Box<dyn Gateway>) -> Badchild {
    Badchild {
        policy: Policy {
            resource: "shell".to_string(),
            enabled: true,
            required_tier: Some("operator".to_string()),
            rollout_percentage: 100,
            real_target: "moonshine://real".to_string(),
            decoy_target: "shadow://decoy".to_string(),
        },
        shadow: ShadowEngine::default(),
        budget: FleetBudget {
            population_ceiling: 10,
            min_breeders: 1,
        },
        fleet: FleetProfile {
            breeders: 1,
            reproductive_void: 0,
            scouts: 0,
            vent_burden: 0,
        },
        revocation: RevocationSet::new(),
        gateway,
    }
}

/// Pick the gateway: the real, contained moonshine when `MONSTER_BADCHILD_REAL=1`,
/// otherwise the in-process mock. Never silently fakes a real session.
fn pick_gateway() -> Box<dyn Gateway> {
    let real = std::env::var("MONSTER_BADCHILD_REAL")
        .map(|v| v == "1" || v.eq_ignore_ascii_case("true"))
        .unwrap_or(false);
    if real {
        Box::new(ProcessGateway::from_env())
    } else {
        Box::new(MockGateway)
    }
}

fn label(verdict: &Verdict) -> &'static str {
    match verdict {
        Verdict::Allow { .. } => "ALLOW   -> real moonshine",
        Verdict::Redirect { .. } => "REDIRECT-> shadow (looks real)",
        Verdict::Trap { .. } => "TRAP    -> honey-pit then shadow",
    }
}

fn run(bc: &Badchild, who: &str, inc: &Incoming) {
    let out = bc.decide(inc);
    let sigs = if out.signatures.is_empty() {
        "none".to_string()
    } else {
        out.signatures.join(",")
    };
    println!(
        "{:<24} status={} {:<32} {:>4}ms key={} body={:?}",
        who,
        out.response.status,
        label(&out.verdict),
        out.response.latency_budget_ms,
        out.state_key.to_hex(),
        out.response.body.trim_end(),
    );
    if out.degraded {
        println!("{:<24} (Allow degraded to shadow: fleet budget exhausted)", "");
    }
    let _ = sigs;
}

fn main() {
    let args: Vec<String> = std::env::args().collect();

    // The portal destination process: serves only the key-seeded shadow world.
    if args.get(1).map(String::as_str) == Some("shadow-serve") {
        let addr = args.get(2).cloned().unwrap_or_else(|| "127.0.0.1:8788".to_string());
        println!("monster-badchild shadow process on http://{addr} (rebuilds worlds from the portal key alone)");
        if let Err(e) = server::shadow_serve(&addr) {
            eprintln!("shadow-serve error: {e}");
            std::process::exit(1);
        }
        return;
    }

    if args.get(1).map(String::as_str) == Some("serve") {
        let addr = args.get(2).cloned().unwrap_or_else(|| "127.0.0.1:8787".to_string());
        let shadow_addr = std::env::var("MONSTER_BADCHILD_SHADOW_ADDR").ok().filter(|s| !s.is_empty());
        let bc = rogue(pick_gateway());
        match &shadow_addr {
            Some(s) => println!("monster-badchild serving on http://{addr} (every response 200; observed/unauthorized PORTALED to shadow process {s})"),
            None => println!("monster-badchild serving on http://{addr} (admit-all, deny-destination; every response is 200; shadow in-process)"),
        }
        if let Err(e) = server::serve_with_shadow(&addr, bc, shadow_addr) {
            eprintln!("serve error: {e}");
            std::process::exit(1);
        }
        return;
    }

    let bc = rogue(pick_gateway());

    // Mint a real, self-rooted UCAN with a0n-auth (the replacement for
    // moonshine's cosmetic HMAC). The operator-tier callers below present it; the
    // unauthenticated caller presents nothing. Capabilities/tier are honored only
    // when the token verifies, so an unauthenticated caller cannot claim a tier.
    let kp = Keypair::generate();
    let token = issue(&kp, kp.did(), &[], 3600, &IssueOptions::default())
        .expect("mint operator UCAN");

    println!("monster-badchild: admit-all, deny-destination. every caller below gets status 200.\n");

    // 1. Authorized operator, with a valid token, quiet. Reaches the real shell.
    run(
        &bc,
        "authorized operator",
        &Incoming {
            token: Some(token.clone()),
            command: "pwd".to_string(),
            method: "POST".to_string(),
            tier: Some("operator".to_string()),
            capabilities: vec!["force_enable".to_string()],
            ledger: ObservationLedger::default(),
            observer: Observer::default(),
        },
    );

    // 2. Unauthenticated caller claiming operator tier. Token absent -> tier and
    //    capabilities are stripped; gets through, lands in shadow.
    run(
        &bc,
        "unauthenticated claimer",
        &Incoming {
            token: None,
            command: "whoami".to_string(),
            method: "POST".to_string(),
            tier: Some("operator".to_string()),
            capabilities: vec!["force_enable".to_string()],
            ledger: ObservationLedger::default(),
            observer: Observer::default(),
        },
    );

    // 3. Path enumerator with a valid operator token. Authorized, but recognized
    //    as an observer -> trapped anyway. The rogue never gets made.
    run(
        &bc,
        "path enumerator (authed)",
        &Incoming {
            token: Some(token.clone()),
            command: "ls /".to_string(),
            method: "GET".to_string(),
            tier: Some("operator".to_string()),
            capabilities: vec!["force_enable".to_string()],
            ledger: ObservationLedger {
                distinct_paths: 128,
                region_size: 1024,
                defended_overlay: 8,
                ..ObservationLedger::default()
            },
            observer: Observer {
                fingerprint: "enum-1".to_string(),
                curiosity: 96,
            },
        },
    );

    // 4. Slowloris with a valid operator token. Recognized via the Zenonic
    //    witness -> trapped despite being authorized.
    run(
        &bc,
        "slowloris (authed)",
        &Incoming {
            token: Some(token.clone()),
            command: "cat /etc/passwd".to_string(),
            method: "POST".to_string(),
            tier: Some("operator".to_string()),
            capabilities: vec!["force_enable".to_string()],
            ledger: ObservationLedger {
                gap: Gap { num: 1, denom: 1 },
                gap_iterations: 32,
                ..ObservationLedger::default()
            },
            observer: Observer {
                fingerprint: "slow-1".to_string(),
                curiosity: 40,
            },
        },
    );

    // The wormhole: the shadow world is a pure function of the portal key, so an
    // observer portaled to a different process (a fresh ShadowWorld from the same
    // key) lands in the identical decoy. Proven in bitwise/lean/PortalWormhole.lean.
    println!();
    let key = world_key("enum-1");
    let process_a = ShadowWorld::from_key(key);
    let process_b = ShadowWorld::from_key(key); // a "different process", same key
    println!("wormhole: observer 'enum-1' key={}", key.to_hex());
    for cmd in ["pwd", "whoami", "ls"] {
        let a = process_a.run(cmd).trim_end().to_string();
        let b = process_b.run(cmd).trim_end().to_string();
        let same = if a == b { "identical" } else { "DIVERGED" };
        println!("  {:<7} process A {:<28} process B {:<28} [{}]", cmd, format!("{a:?}"), format!("{b:?}"), same);
    }
}
